#!/usr/bin/env python3
import sys
from atcoder import dsu
from bisect import bisect_left
from collections import defaultdict
from collections import deque
# import pypyjit
# pypyjit.set_param(inlining=0)     # or pypyjit.set_param('max_unroll_recursion=-1')

sys.setrecursionlimit(10 ** 6)

INF = 2 ** 64 - 1


# Generated by 2.16.0 https://github.com/kyuridenamida/atcoder-tools  (tips: You use the default template now. You can remove this line by using your custom template)
def main():
    N = int(input())
    DATA = [list(map(int, input().split())) for _ in range(N)]

    b_sum, w_sum = 0, 0
    for w, _, b in DATA:
        w_sum += w
        b_sum += b

    w_max = w_sum // 2

    mdp = [[-INF] * (w_max + 1) for _ in range(2)]

    cur_idx = 0
    nxt_idx = 1

    mdp[0][0] = b_sum

    for i, (w, h, b) in enumerate(DATA):
        if h - b <= 0:
            continue
        for j in range(w_max + 1):
            mdp[nxt_idx][j] = -INF

        for j in range(w_max + 1):
            mdp[nxt_idx][j] = max(mdp[nxt_idx][j], mdp[cur_idx][j])
            if j + w <= w_max:
                mdp[nxt_idx][j + w] = max(mdp[nxt_idx][j + w], mdp[cur_idx][j] + (h - b))

        cur_idx, nxt_idx = nxt_idx, cur_idx

    print(max(mdp[cur_idx]))
    

if __name__ == '__main__':
    main()
